arguments.file_text:
@using System.Timers
@implements IDisposable
@inject INotificationService NotificationService

<span class="notification-badge" @onclick="HandleClick">
    @if (unreadCount > 0)
    {
        <span class="badge">@unreadCount</span>
    }
</span>

@code {
    [Parameter]
    public EventCallback OnClick { get; set; }

    private int unreadCount;
    private Timer? pollingTimer;

    protected override async Task OnInitializedAsync()
    {
        unreadCount = await NotificationService.GetUnreadCountAsync();
        NotificationService.OnNotificationReceived += HandleNotificationReceived;

        pollingTimer = new Timer(30_000);
        pollingTimer.Elapsed += PollUnreadCount;
        pollingTimer.Start();
    }

    private void HandleNotificationReceived(Notification notification)
    {
        unreadCount++;
        InvokeAsync(StateHasChanged);
    }

    private async void PollUnreadCount(object? sender, ElapsedEventArgs e)
    {
        unreadCount = await NotificationService.GetUnreadCountAsync();
        await InvokeAsync(StateHasChanged);
    }

    private async Task HandleClick()
    {
        await OnClick.InvokeAsync();
    }

    public void Dispose()
    {
        NotificationService.OnNotificationReceived -= HandleNotificationReceived;

        if (pollingTimer is not null)
        {
            pollingTimer.Elapsed -= PollUnreadCount;
            pollingTimer.Stop();
            pollingTimer.Dispose();
        }
    }
}

